const input = $input.first()?.json ?? {};

const primaryModel = String(input.model ?? 'gemini-3-flash-preview').trim();
const fallbackModel = String(input.fallback_model ?? 'gemini-2.5-pro').trim();
const model = primaryModel || 'gemini-3-flash-preview';
const cliproxyBaseUrl = String(input.cliproxy_base_url ?? '').replace(/\/$/, '');
const cliproxyClientKey = String(input.cliproxy_client_key ?? '');
const openaiModel = String(input.openai_model ?? 'gpt-5.4').trim() || 'gpt-5.4';
const scoreThresholdRaw = Number(input.qc_score_warning_threshold ?? 7);
const qcScoreWarningThreshold = Number.isFinite(scoreThresholdRaw)
  ? Math.min(10, Math.max(0, Math.floor(scoreThresholdRaw)))
  : 7;
const reviewerWaitTimeoutSecondsRaw = Number(input.reviewer_wait_timeout_seconds ?? 900);
const reviewerWaitTimeoutSeconds = Number.isFinite(reviewerWaitTimeoutSecondsRaw) && reviewerWaitTimeoutSecondsRaw > 10
  ? Math.floor(reviewerWaitTimeoutSecondsRaw)
  : 900;
const userInput = String(input.user_input ?? '').trim();
const masterPromptTemplate = String(input.master_prompt_template ?? '').trim();
const maxTurnsRaw = Number(input.max_turns ?? 8);
const maxTurns = Number.isFinite(maxTurnsRaw) && maxTurnsRaw > 0
  ? Math.floor(maxTurnsRaw)
  : 8;
const requestHelper =
  helpers?.httpRequest ??
  (typeof $helpers !== 'undefined' ? $helpers?.httpRequest : undefined);

function baseOutput(overrides = {}) {
  return {
    message: '',
    full_review: '',
    turn_count: 0,
    stop_reason: 'completed',
    model,
    fallback_model: fallbackModel || null,
    fallback_used: false,
    user_input: userInput,
    cliproxy_base_url: cliproxyBaseUrl,
    cliproxy_client_key: cliproxyClientKey,
    openai_model: openaiModel,
    qc_score_warning_threshold: qcScoreWarningThreshold,
    reviewer_wait_timeout_seconds: reviewerWaitTimeoutSeconds,
    ...overrides,
  };
}

function detectControlTag(value) {
  const text = String(value ?? '').replace(/\r\n/g, '\n');
  const lines = text.split('\n');

  let cursor = 0;
  let foundTag = null;

  for (const line of lines) {
    const markerMatch = line.match(/^\s*-\s*(CONTINUE|END)\s*-\s*$/i);
    if (markerMatch) {
      const markerOffset = line.search(/-/);
      const markerStart = cursor + (markerOffset >= 0 ? markerOffset : 0);
      const markerEnd = cursor + line.length;
      foundTag = {
        type: markerMatch[1].toLowerCase(),
        start: markerStart,
        end: markerEnd,
      };
    }

    cursor += line.length + 1;
  }

  return foundTag;
}

function stripControlTag(value, controlTag, options = {}) {
  const text = String(value ?? '').replace(/\r\n/g, '\n').trimEnd();
  if (!controlTag) {
    return text;
  }

  if (controlTag.type === 'end' && options.keepEndTag === true) {
    return text.slice(0, controlTag.end).trimEnd();
  }

  return text.slice(0, controlTag.start).trimEnd();
}

function shouldFallbackForCapacity(errorMessage) {
  const text = String(errorMessage ?? '');
  return /429|RESOURCE_EXHAUSTED|MODEL_CAPACITY_EXHAUSTED|No capacity available|cooling down/i.test(text);
}

function buildMasterPrompt(template, bookInput) {
  return String(template ?? '').replaceAll('{{USER_INPUT}}', String(bookInput ?? ''));
}

if (!userInput) {
  return [{
    json: baseOutput({
      message: 'Vui lòng nhập tên sách và tác giả trong chat. Ví dụ: Sách Nhà Giả Kim của tác giả Paulo Coelho.',
    }),
  }];
}

if (!cliproxyBaseUrl || !cliproxyClientKey) {
  return [{
    json: baseOutput({
      message: 'Thiếu cấu hình CLIProxy (base URL hoặc client key).',
      stop_reason: 'api_error',
    }),
  }];
}

if (!masterPromptTemplate) {
  return [{
    json: baseOutput({
      message: 'Thiếu master prompt template (field `master_prompt_template`).',
      stop_reason: 'api_error',
    }),
  }];
}

if (typeof requestHelper !== 'function') {
  return [{
    json: baseOutput({
      message: 'Thiếu helper HTTP trong Code node runtime (cần `helpers.httpRequest`).',
      stop_reason: 'api_error',
    }),
  }];
}

const masterPrompt = buildMasterPrompt(masterPromptTemplate, userInput);
const messages = [{ role: 'user', content: masterPrompt }];
const chunks = [];

let stopReason = 'completed';
let apiError = '';
let turnCount = 0;
let activeModel = model;
let fallbackUsed = false;

for (let turn = 1; turn <= maxTurns; turn += 1) {
  try {
    const candidateModels =
      activeModel === primaryModel &&
      fallbackModel &&
      fallbackModel !== primaryModel
        ? [primaryModel, fallbackModel]
        : [activeModel];

    let response;
    let lastError;
    for (let idx = 0; idx < candidateModels.length; idx += 1) {
      const candidateModel = candidateModels[idx];
      try {
        response = await requestHelper({
          method: 'POST',
          url: cliproxyBaseUrl + '/v1/chat/completions',
          headers: {
            Authorization: 'Bearer ' + cliproxyClientKey,
          },
          body: {
            model: candidateModel,
            messages,
            stream: false,
          },
          json: true,
          timeout: 240000,
        });
        if (candidateModel !== activeModel) {
          fallbackUsed = true;
        }
        activeModel = candidateModel;
        break;
      } catch (error) {
        lastError = error;
        const errorText = error?.message ? String(error.message) : String(error);
        const canTryFallback =
          candidateModel === primaryModel &&
          fallbackModel &&
          fallbackModel !== primaryModel &&
          shouldFallbackForCapacity(errorText);
        if (canTryFallback) {
          continue;
        }
        throw error;
      }
    }

    if (!response) {
      throw (lastError ?? new Error('Không nhận được response từ model.'));
    }

    turnCount = turn;

    const chunk = String(response?.choices?.[0]?.message?.content ?? '').trim();
    if (!chunk) {
      break;
    }

    const controlTag = detectControlTag(chunk);
    chunks.push({
      content: chunk,
      controlTag,
    });
    messages.push({ role: 'assistant', content: chunk });

    if (controlTag?.type === 'continue') {
      if (turn >= maxTurns) {
        stopReason = 'max_turns';
        break;
      }

      messages.push({ role: 'user', content: 'Continue' });
      continue;
    }

    if (controlTag?.type === 'end') {
      break;
    }

    break;
  } catch (error) {
    stopReason = 'api_error';
    apiError = error?.message ? String(error.message) : String(error);
    break;
  }
}

const mergedChunks = chunks
  .map((chunk, index) => {
    const isLast = index === chunks.length - 1;
    const keepEndTag = isLast && chunk.controlTag?.type === 'end';
    return stripControlTag(chunk.content, chunk.controlTag, { keepEndTag });
  })
  .filter((chunk) => chunk !== '');

const fullReview = mergedChunks.join('\n\n').trim();
let message = fullReview;

if (stopReason === 'max_turns') {
  const note = '[Lưu ý: Đã đạt giới hạn ' + maxTurns + ' lượt gọi "Continue".]';
  message = fullReview ? fullReview + '\n\n' + note : note;
} else if (stopReason === 'api_error') {
  const note = apiError
    ? '[Lỗi gọi Gemini (' + activeModel + '): ' + apiError + ']'
    : '[Lỗi gọi Gemini: Không rõ nguyên nhân.]';
  message = fullReview ? fullReview + '\n\n' + note : note;
}

if (!message) {
  message = 'Không nhận được nội dung từ Gemini.';
}

return [{
  json: baseOutput({
    message,
    full_review: fullReview,
    turn_count: turnCount,
    stop_reason: stopReason,
    model: activeModel,
    fallback_used: fallbackUsed,
  }),
}];

const input = $json ?? {};

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function detectTrailingControlTag(text) {
  const match = text.match(/(?:^|\n)\s*-\s*(CONTINUE|END)\s*-\s*$/i);
  if (!match) {
    return null;
  }

  const start = typeof match.index === 'number' ? match.index : text.length - match[0].length;
  return {
    type: match[1].toLowerCase(),
    start,
    end: start + match[0].length,
  };
}

function buildFileName(order, id) {
  const orderLabel = String(order).padStart(2, '0');
  const safeId = String(id || 'section')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'section';
  return orderLabel + '_' + safeId + '.txt';
}

const rawReview = normalizeText(input.full_review ?? input.message ?? '');
const trailingTag = detectTrailingControlTag(rawReview);
const reviewBody = trailingTag ? rawReview.slice(0, trailingTag.start).trimEnd() : rawReview;

const sectionRegex = /<<<SECTION\|([^|\n>]+)\|([^\n>]+)>>>\s*([\s\S]*?)\s*<<<END_SECTION>>>/g;
const sections = [];
let match;

while ((match = sectionRegex.exec(reviewBody)) !== null) {
  const id = String(match[1] ?? '').trim();
  const title = String(match[2] ?? '').trim();
  const content = String(match[3] ?? '').trim();
  const order = sections.length + 1;

  sections.push({
    order,
    id,
    title,
    content,
    file_name: buildFileName(order, id),
  });
}

let parseStatus = 'parsed';
let parserWarning = '';

if (!reviewBody) {
  parseStatus = 'empty';
  parserWarning = 'No review content to parse.';
} else if (sections.length === 0) {
  parseStatus = 'fallback_single_section';
  parserWarning = 'Cannot find SECTION markers. Returned full review as one section.';
  sections.push({
    order: 1,
    id: 'full_review',
    title: 'Full Review',
    content: reviewBody,
    file_name: '01_full_review.txt',
  });
}

const introSection = sections.find((section) => section.id === 'intro') ?? null;
const outroSection = sections.find((section) => section.id === 'outro') ?? null;
const partSections = sections.filter((section) => /^part_\d{2}$/i.test(section.id));

return {
  ...input,
  review_sections: sections,
  review_intro: introSection?.content ?? '',
  review_parts: partSections,
  review_outro: outroSection?.content ?? '',
  review_sections_count: sections.length,
  review_control_tag: trailingTag?.type ?? null,
  review_parse_status: parseStatus,
  review_parser_warning: parserWarning || null,
};

const input = $json ?? {};

const requestHelper =
  helpers?.httpRequest ??
  (typeof $helpers !== 'undefined' ? $helpers?.httpRequest : undefined);

const cliproxyBaseUrl = String(input.cliproxy_base_url ?? '').replace(/\/$/, '');
const cliproxyClientKey = String(input.cliproxy_client_key ?? '').trim();
const openaiModel = String(input.openai_model ?? 'gpt-5.4').trim() || 'gpt-5.4';
const reviewerTimeoutRaw = Number(input.reviewer_wait_timeout_seconds ?? 900);
const reviewerTimeoutSeconds = Number.isFinite(reviewerTimeoutRaw) && reviewerTimeoutRaw > 30
  ? Math.floor(reviewerTimeoutRaw)
  : 900;
const qcThresholdRaw = Number(input.qc_score_warning_threshold ?? 7);
const qcScoreWarningThreshold = Number.isFinite(qcThresholdRaw)
  ? Math.min(10, Math.max(0, Math.floor(qcThresholdRaw)))
  : 7;

const telegramBotToken = String(input.telegram_bot_token ?? '').trim();
const telegramChatId = String(input.telegram_chat_id ?? '').trim();
const userInput = String(input.user_input ?? '').trim();
const metadataPromptTemplate = String(input.metadata_prompt_template ?? '').trim();
const qcPromptTemplate = String(input.qc_prompt_template ?? '').trim();
const reviewRevisionPromptTemplate = String(input.review_revision_prompt_template ?? '').trim();
const masterPromptTemplate = String(input.master_prompt_template ?? '').trim();

let reviewText = String(input.full_review ?? input.message ?? '').trim();
let reviewIntro = String(input.review_intro ?? '').trim();
let reviewOutro = String(input.review_outro ?? '').trim();

const METADATA_FIELDS = ['title', 'caption', 'thumbnail_text', 'hashtags'];

function nowToken() {
  const rnd = Math.random().toString(36).slice(2, 8);
  return Date.now().toString(36) + rnd;
}

function stripControlTags(text) {
  const normalized = String(text ?? '').replace(/\r\n/g, '\n').trim();
  return normalized.replace(/(?:\n|^)\s*-\s*(CONTINUE|END)\s*-\s*$/i, '').trim();
}

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function buildMasterPrompt(template, bookInput) {
  return String(template ?? '').replaceAll('{{USER_INPUT}}', String(bookInput ?? '')).trim();
}

function clipContextText(value, maxChars) {
  const text = String(value ?? '').trim();
  const limit = Number(maxChars);

  if (!text || !Number.isFinite(limit) || limit <= 0) {
    return {
      text: '',
      truncated: text.length > 0,
    };
  }

  if (text.length <= limit) {
    return {
      text,
      truncated: false,
    };
  }

  if (limit < 500) {
    return {
      text: text.slice(0, limit),
      truncated: true,
    };
  }
  const marker = '\\n...[truncated_for_input_limit]...\\n';
  const head = Math.max(200, Math.floor(limit * 0.7));
  const tail = Math.max(100, limit - head - marker.length);

  return {
    text: text.slice(0, head) + marker + text.slice(-tail),
    truncated: true,
  };
}

function shouldRetryWithTrimmedContext(errorMessage) {
  const text = String(errorMessage ?? '');
  return /(context length|maximum context|max context|context window|prompt is too long|request too large|too many tokens|token limit|413|input is too long)/i.test(text);
}

function splitMessage(text, maxLen = 3500) {
  const raw = String(text ?? '').trim();
  if (!raw) return [];

  const parts = [];
  let cursor = 0;

  while (cursor < raw.length) {
    const remain = raw.length - cursor;
    if (remain <= maxLen) {
      parts.push(raw.slice(cursor));
      break;
    }

    const slice = raw.slice(cursor, cursor + maxLen);
    let cut = Math.max(slice.lastIndexOf('\n\n'), slice.lastIndexOf('\n'), slice.lastIndexOf(' '));
    if (cut < Math.floor(maxLen * 0.5)) cut = maxLen;
    parts.push(raw.slice(cursor, cursor + cut).trim());
    cursor += cut;
  }

  return parts.filter(Boolean);
}

function parseJsonObject(rawText) {
  const raw = String(rawText ?? '').trim();
  if (!raw) return null;

  try { return JSON.parse(raw); } catch (_) {}

  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) {
    try { return JSON.parse(fence[1]); } catch (_) {}
  }

  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try { return JSON.parse(raw.slice(first, last + 1)); } catch (_) {}
  }

  return null;
}

function clampScore(value, fallback = 6) {
  const num = Number(value);
  if (!Number.isFinite(num)) return fallback;
  if (num < 0) return 0;
  if (num > 10) return 10;
  return Math.round(num * 10) / 10;
}

function normalizeRisk(value) {
  const risk = String(value ?? '').trim().toLowerCase();
  if (risk === 'low' || risk === 'med' || risk === 'high') return risk;
  return 'med';
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  }
  if (typeof value === 'string') {
    return value
      .split(/[\n,]+/)
      .map((item) => item.trim())
      .filter(Boolean);
  }
  return [];
}

function normalizeFeedback(value, fallback = '') {
  const raw = String(value ?? '').replace(/\s+/g, ' ').trim();
  const text = raw || String(fallback ?? '').replace(/\s+/g, ' ').trim();
  if (!text) return '';

  const words = text.split(/\s+/).filter(Boolean);
  if (words.length <= 200) {
    return text;
  }

  return words.slice(0, 200).join(' ');
}

function normalizeHashtags(value) {
  const tags = normalizeList(value)
    .map((item) => item.replace(/^#*/, '').replace(/\s+/g, ''))
    .filter(Boolean)
    .map((item) => '#' + item.toLowerCase());

  const unique = [];
  for (const tag of tags) {
    if (!unique.includes(tag)) unique.push(tag);
  }

  return unique.slice(0, 15);
}

function buildScoreWarnings(scores, threshold) {
  const map = {
    Hook: scores.hook_score,
    Clarity: scores.clarity_score,
    Originality: scores.originality_score,
    'Practical value': scores.practical_value_score,
  };

  return Object.entries(map)
    .filter(([, score]) => Number(score) < threshold)
    .map(([label, score]) => label + ' score=' + score + ' < ' + threshold);
}

function ensureKeepOthersInstruction(instruction) {
  const base = safeText(instruction);
  if (!base) return '';

  const keepPattern = /những\s+thứ\s+khác\s+giữ\s+nguyên|nhung\s+thu\s+khac\s+giu\s+nguyen|keep\s+(the\s+)?other\s+fields\s+unchanged/i;
  if (keepPattern.test(base)) {
    return base;
  }

  return base + '. Những thứ khác giữ nguyên.';
}

function detectMetadataTargets(instruction) {
  const text = String(instruction ?? '').toLowerCase();
  const targets = new Set();

  if (!text) return targets;

  if (/(\btitle\b|ti[eê]u\s*đ[eề]\b|tieu\s*de\b)/i.test(text)) {
    targets.add('title');
  }

  if (/(\bcaption\b|ch[uú]\s*th[ií]ch|m[oô]\s*t[aả]\s*ng[aă]n)/i.test(text)) {
    targets.add('caption');
  }

  if (/(\bthumbnail\b|\bthumb\b|thumbnail\s*text|anh\s*bia|ảnh\s*bìa)/i.test(text)) {
    targets.add('thumbnail_text');
  }

  if (/(\bhashtag\b|hash\s*tag|\btags?\b)/i.test(text)) {
    targets.add('hashtags');
  }

  return targets;
}

async function callOpenAI(messages, options = {}) {
  if (!cliproxyBaseUrl || !cliproxyClientKey || typeof requestHelper !== 'function') {
    throw new Error('Missing CLIProxy/OpenAI configuration or HTTP helper.');
  }

  const body = {
    model: openaiModel,
    messages,
    stream: false,
  };

  if (options.jsonObject === true) {
    body.response_format = { type: 'json_object' };
  }

  return await requestHelper({
    method: 'POST',
    url: cliproxyBaseUrl + '/v1/chat/completions',
    headers: {
      Authorization: 'Bearer ' + cliproxyClientKey,
    },
    body,
    json: true,
    timeout: Number(options.timeoutMs ?? 180000),
  });
}

async function runQc(review, introText, outroText) {
  const fallback = {
    qc_checks: [],
    qc_issues: ['QC fallback.'],
    feedback: 'Chưa có feedback QC chi tiết.',
    hook_score: 6,
    clarity_score: 6,
    originality_score: 6,
    practical_value_score: 6,
    risk_level: 'med',
    score_warnings: [],
    qc_status: 'fallback',
    qc_error: null,
  };

  try {
    const promptPayload = {
      task: 'QC a Vietnamese long-form book review script.',
      policy: {
        quote_policy: 'Only accept direct quote if source certainty is high. Otherwise mark warn.',
        no_rewrite: true,
      },
      input: {
        request: userInput,
        intro_excerpt: String(introText ?? '').slice(0, 1200),
        outro_excerpt: String(outroText ?? '').slice(0, 1200),
        review_excerpt: String(review ?? '').slice(0, 7000),
      },
      required_json_schema: {
        hook: 0,
        clarity: 0,
        originality: 0,
        practical: 0,
        risk: 'low|med|high',
        feedback: 'string (Vietnamese, actionable, <= 200 words)',
        qc_issues: ['string (optional)'],
      },
    };

    const response = await callOpenAI([
      {
        role: 'system',
        content: safeText(qcPromptTemplate, 'You are a strict content QC editor. Return JSON only, no markdown.'),
      },
      {
        role: 'user',
        content: JSON.stringify(promptPayload),
      },
    ], { jsonObject: true });

    const content = String(response?.choices?.[0]?.message?.content ?? '').trim();
    const parsed = parseJsonObject(content);
    if (!parsed || typeof parsed !== 'object') {
      throw new Error('QC response is not valid JSON object.');
    }

    const qcChecks = Array.isArray(parsed.qc_checks) ? parsed.qc_checks : [];
    const qcIssues = normalizeList(parsed.qc_issues ?? parsed.issues);

    const hookRaw = parsed?.hook ?? parsed?.scores?.hook;
    const clarityRaw = parsed?.clarity ?? parsed?.scores?.clarity;
    const originalityRaw = parsed?.originality ?? parsed?.scores?.originality;
    const practicalRaw = parsed?.practical ?? parsed?.scores?.practical ?? parsed?.scores?.practical_value;
    const riskRaw = parsed?.risk ?? parsed?.risk_level;

    const derivedIssues = qcIssues.length > 0
      ? qcIssues
      : qcChecks
          .filter((check) => String(check?.status ?? '').toLowerCase() !== 'pass')
          .map((check) => String(check?.note ?? '').trim())
          .filter(Boolean);

    const feedbackFallback = derivedIssues.slice(0, 3).join('; ');
    const qc = {
      qc_checks: qcChecks,
      qc_issues: derivedIssues,
      feedback: normalizeFeedback(parsed?.feedback, feedbackFallback),
      hook_score: clampScore(hookRaw, 6),
      clarity_score: clampScore(clarityRaw, 6),
      originality_score: clampScore(originalityRaw, 6),
      practical_value_score: clampScore(practicalRaw, 6),
      risk_level: normalizeRisk(riskRaw),
      score_warnings: [],
      qc_status: 'generated',
      qc_error: null,
    };

    qc.score_warnings = buildScoreWarnings(qc, qcScoreWarningThreshold);
    return qc;
  } catch (error) {
    fallback.qc_error = error?.message ? String(error.message) : String(error);
    fallback.score_warnings = buildScoreWarnings(fallback, qcScoreWarningThreshold);
    return fallback;
  }
}

function extractSectionText(review, id) {
  const regex = new RegExp('<<<SECTION\\|' + id + '\\|[^>]+>>>\\s*([\\s\\S]*?)\\s*<<<END_SECTION>>>', 'i');
  const match = String(review ?? '').match(regex);
  return match ? String(match[1] ?? '').trim() : '';
}

async function reviseReview(currentReview, instruction) {
  const instructionText = String(instruction ?? '').trim();
  const masterPromptInjected = buildMasterPrompt(masterPromptTemplate, userInput);
  const fullReviewText = String(currentReview ?? '').trim();

  function buildRevisePrompt(reviewText, masterPromptText, flags = {}) {
    return {
      task: 'Revise Vietnamese book review script by reviewer instruction.',
      constraints: {
        keep_section_contract: true,
        keep_ids: ['intro', 'part_01+', 'outro'],
        keep_language: 'vi',
        output: 'full review text only',
        follow_master_prompt: true,
      },
      instruction: instructionText,
      current_review: String(reviewText ?? '').trim(),
      original_request_context: {
        user_input: userInput,
        master_prompt_injected: String(masterPromptText ?? '').trim(),
        master_prompt_truncated: Boolean(flags.masterPromptTruncated),
        current_review_truncated: Boolean(flags.reviewTruncated),
      },
    };
  }

  async function callRevise(promptPayload) {
    const response = await callOpenAI([
      {
        role: 'system',
        content: safeText(reviewRevisionPromptTemplate, 'You are a senior script editor. Return only revised review text in SECTION format. No markdown.'),
      },
      {
        role: 'user',
        content: JSON.stringify(promptPayload),
      },
    ]);

    const revised = String(response?.choices?.[0]?.message?.content ?? '').trim();
    if (!revised) {
      throw new Error('Empty revised review from AI.');
    }

    return stripControlTags(revised);
  }

  const fullPrompt = buildRevisePrompt(fullReviewText, masterPromptInjected, {
    masterPromptTruncated: false,
    reviewTruncated: false,
  });

  try {
    return await callRevise(fullPrompt);
  } catch (error) {
    const errorText = error?.message ? String(error.message) : String(error);
    if (!shouldRetryWithTrimmedContext(errorText)) {
      throw error;
    }

    const masterPromptPack = clipContextText(masterPromptInjected, 9000);
    const reviewBudgetBase = 26000;
    const reserveChars = instructionText.length + masterPromptPack.text.length + 2500;
    const reviewBudget = Math.max(7000, Math.min(24000, reviewBudgetBase - reserveChars));
    const reviewPack = clipContextText(fullReviewText, reviewBudget);

    const clippedPrompt = buildRevisePrompt(reviewPack.text, masterPromptPack.text, {
      masterPromptTruncated: masterPromptPack.truncated,
      reviewTruncated: reviewPack.truncated,
    });

    return await callRevise(clippedPrompt);
  }
}

async function generateMetadataBundle(review, instruction, previousMetadata) {
  const reviewerInstruction = String(instruction ?? '').trim();
  const adjustedInstruction = ensureKeepOthersInstruction(reviewerInstruction);
  const requestedTargets = detectMetadataTargets(adjustedInstruction);

  const promptPayload = {
    task: previousMetadata ? 'Refine existing metadata for a Vietnamese book-review video.' : 'Generate metadata for a Vietnamese book-review video.',
    requirements: {
      output: 'json_only',
      fields: ['title', 'caption', 'thumbnail_text', 'hashtags'],
      style: 'high-retention, concrete, non-clickbait',
      language: 'vi',
      keep_unmentioned_fields: true,
      never_output_fields: ['youtube_description_long', 'description', 'video_description'],
    },
    request: userInput,
    reviewer_instruction: adjustedInstruction,
    previous_metadata: previousMetadata ?? null,
    review_excerpt: String(review ?? '').slice(0, 7000),
  };

  const systemPrompt = safeText(
    metadataPromptTemplate,
    'You are a short-video growth strategist. Return JSON only with exactly these keys: title, caption, thumbnail_text, hashtags.'
  );

  const response = await callOpenAI([
    {
      role: 'system',
      content: systemPrompt,
    },
    {
      role: 'user',
      content: JSON.stringify(promptPayload),
    },
  ], { jsonObject: true });

  const content = String(response?.choices?.[0]?.message?.content ?? '').trim();
  const parsed = parseJsonObject(content);
  if (!parsed || typeof parsed !== 'object') {
    throw new Error('Metadata response is not valid JSON object.');
  }

  const resolved = {
    title: safeText(parsed.title, previousMetadata?.title || 'Tiêu đề video'),
    caption: safeText(parsed.caption, previousMetadata?.caption || 'Caption video'),
    thumbnail_text: safeText(parsed.thumbnail_text, previousMetadata?.thumbnail_text || 'Thumbnail text'),
    hashtags: normalizeHashtags(parsed.hashtags),
  };

  if (resolved.hashtags.length === 0) {
    resolved.hashtags = Array.isArray(previousMetadata?.hashtags) && previousMetadata.hashtags.length > 0
      ? previousMetadata.hashtags
      : ['#bookreview', '#selfhelp', '#phattrienbanthan'];
  }

  const hasSelectiveInstruction =
    Boolean(previousMetadata) &&
    adjustedInstruction.length > 0 &&
    requestedTargets.size > 0 &&
    requestedTargets.size < METADATA_FIELDS.length;

  if (hasSelectiveInstruction) {
    if (!requestedTargets.has('title')) {
      resolved.title = safeText(previousMetadata?.title, resolved.title);
    }
    if (!requestedTargets.has('caption')) {
      resolved.caption = safeText(previousMetadata?.caption, resolved.caption);
    }
    if (!requestedTargets.has('thumbnail_text')) {
      resolved.thumbnail_text = safeText(previousMetadata?.thumbnail_text, resolved.thumbnail_text);
    }
    if (!requestedTargets.has('hashtags')) {
      resolved.hashtags = Array.isArray(previousMetadata?.hashtags) && previousMetadata.hashtags.length > 0
        ? previousMetadata.hashtags
        : resolved.hashtags;
    }
  }

  return resolved;
}

function parseDecisionFromText(text, stage) {
  const lower = String(text ?? '').trim().toLowerCase();
  if (!lower) return null;

  if (/^(dung|dừng|stop|\/stop)$/.test(lower)) {
    return { action: 'stop', instruction: '' };
  }

  if (/^(tiep|tiếp|continue|\/continue)$/.test(lower)) {
    return { action: 'continue', instruction: '' };
  }

  const changeMatch = lower.match(/^(doi|đổi|change|\/doi)\s*(.*)$/i);
  if (changeMatch) {
    const instruction = String(changeMatch[2] ?? '').trim();
    return { action: 'change', instruction };
  }

  if (stage === 'review' || stage === 'metadata') {
    return { action: 'change', instruction: String(text ?? '').trim() };
  }

  return null;
}

async function telegramApi(method, params = {}, useGet = false) {
  const url = 'https://api.telegram.org/bot' + telegramBotToken + '/' + method;
  return await requestHelper({
    method: useGet ? 'GET' : 'POST',
    url,
    qs: useGet ? params : undefined,
    body: useGet ? undefined : params,
    json: true,
    timeout: 60000,
  });
}

async function sendTelegramMessage(text, inlineKeyboardRows) {
  if (!telegramBotToken || !telegramChatId) return;

  const payload = {
    chat_id: telegramChatId,
    text: String(text ?? '').slice(0, 4000),
  };

  if (Array.isArray(inlineKeyboardRows) && inlineKeyboardRows.length > 0) {
    payload.reply_markup = {
      inline_keyboard: inlineKeyboardRows,
    };
  }

  await telegramApi('sendMessage', payload, false);
}

async function sendLongReviewPreview(prefixText, fullText) {
  if (prefixText) {
    await sendTelegramMessage(prefixText);
  }

  const chunks = splitMessage(fullText, 3500);
  for (let index = 0; index < chunks.length; index += 1) {
    const chunk = chunks[index];
    const marker = chunks.length > 1 ? '[Phần ' + (index + 1) + '/' + chunks.length + ']\n' : '';
    await sendTelegramMessage(marker + chunk);
  }
}

async function getStartOffset() {
  if (!telegramBotToken || !telegramChatId) return 0;

  try {
    const response = await telegramApi('getUpdates', {
      timeout: 0,
      limit: 100,
      allowed_updates: JSON.stringify(['message', 'callback_query']),
    }, true);

    const updates = Array.isArray(response?.result) ? response.result : [];
    let maxId = 0;
    for (const item of updates) {
      const id = Number(item?.update_id ?? 0);
      if (Number.isFinite(id) && id > maxId) maxId = id;
    }
    return maxId > 0 ? maxId + 1 : 0;
  } catch (_) {
    return 0;
  }
}

async function waitForReviewerAction(stagePrefix, sessionToken, initialOffset, timeoutSeconds) {
  const deadline = Date.now() + timeoutSeconds * 1000;
  let offset = Number(initialOffset ?? 0);
  let needInstruction = false;

  while (Date.now() < deadline) {
    let updates = [];
    try {
      const response = await telegramApi('getUpdates', {
        timeout: 20,
        offset,
        allowed_updates: JSON.stringify(['message', 'callback_query']),
      }, true);
      updates = Array.isArray(response?.result) ? response.result : [];
    } catch (_) {
      updates = [];
    }

    for (const update of updates) {
      const updateId = Number(update?.update_id ?? 0);
      if (Number.isFinite(updateId) && updateId >= offset) {
        offset = updateId + 1;
      }

      const callbackData = String(update?.callback_query?.data ?? '').trim();
      const callbackId = String(update?.callback_query?.id ?? '').trim();
      const callbackChatId = String(update?.callback_query?.message?.chat?.id ?? '').trim();

      if (callbackData && callbackChatId === telegramChatId) {
        if (callbackId) {
          try {
            await telegramApi('answerCallbackQuery', {
              callback_query_id: callbackId,
            }, false);
          } catch (_) {}
        }

        const expectedPrefix = stagePrefix + '_';
        if (callbackData.includes(':' + sessionToken) && callbackData.startsWith(expectedPrefix)) {
          if (callbackData.startsWith(stagePrefix + '_continue:')) {
            return { action: 'continue', instruction: '', offset };
          }
          if (callbackData.startsWith(stagePrefix + '_stop:')) {
            return { action: 'stop', instruction: '', offset };
          }
          if (callbackData.startsWith(stagePrefix + '_change:')) {
            needInstruction = true;
            await sendTelegramMessage('Bạn muốn đổi gì? Hãy nhắn: `doi <noi_dung_muon_sua>`');
            continue;
          }
        }
      }

      const messageText = String(update?.message?.text ?? '').trim();
      const messageChatId = String(update?.message?.chat?.id ?? '').trim();
      if (!messageText || messageChatId !== telegramChatId) {
        continue;
      }

      const decision = parseDecisionFromText(messageText, stagePrefix === 'rvw' ? 'review' : 'metadata');
      if (!decision) {
        continue;
      }

      if (decision.action === 'change' && !decision.instruction) {
        needInstruction = true;
        await sendTelegramMessage('Mình đã nhận lệnh đổi. Hãy gửi chi tiết dạng: `doi <noi_dung_muon_sua>`');
        continue;
      }

      if (needInstruction && decision.action === 'change' && decision.instruction) {
        return { action: 'change', instruction: decision.instruction, offset };
      }

      return { action: decision.action, instruction: decision.instruction, offset };
    }
  }

  return { action: 'continue', instruction: '', offset, timeout: true };
}

const responseBase = {
  ...input,
  reviewer_session_token: nowToken(),
  reviewer_decision: 'continue',
  reviewer_gate_status: 'completed',
  reviewer_commands: [],
  metadata_status: 'pending',
  metadata_error: null,
  metadata: null,
};

if (!reviewText) {
  responseBase.reviewer_gate_status = 'skip_no_review';
  responseBase.reviewer_decision = 'stop';
  responseBase.stop_reason = 'review_empty';
  responseBase.message = 'Không có nội dung review để reviewer duyệt.';
  return responseBase;
}

if (!reviewIntro) {
  reviewIntro = extractSectionText(reviewText, 'intro');
}
if (!reviewOutro) {
  reviewOutro = extractSectionText(reviewText, 'outro');
}

let qc = await runQc(reviewText, reviewIntro, reviewOutro);

if ((!telegramBotToken || !telegramChatId) || typeof requestHelper !== 'function') {
  responseBase.reviewer_gate_status = 'skip_no_telegram';
  responseBase.metadata_status = 'skip';
  responseBase.stop_reason = String(input.stop_reason ?? 'completed');
  responseBase.message = reviewText;
  responseBase.metadata = null;
  return {
    ...responseBase,
    ...qc,
    full_review: reviewText,
    review_intro: reviewIntro,
    review_outro: reviewOutro,
  };
}

let offset = await getStartOffset();
let metadata = null;
const commandLogs = [];
const sessionToken = responseBase.reviewer_session_token;

const reviewButtons = [[
  { text: 'Tiếp tục', callback_data: 'rvw_continue:' + sessionToken },
  { text: 'Dừng', callback_data: 'rvw_stop:' + sessionToken },
  { text: 'Đổi', callback_data: 'rvw_change:' + sessionToken },
]];

const metadataButtons = [[
  { text: 'Tiếp tục', callback_data: 'meta_continue:' + sessionToken },
  { text: 'Dừng', callback_data: 'meta_stop:' + sessionToken },
  { text: 'Đổi', callback_data: 'meta_change:' + sessionToken },
]];

let reviewerStopped = false;
const maxReviewAdjustRounds = 6;
let reviewRound = 0;

while (reviewRound <= maxReviewAdjustRounds) {
  const qcSummary = [
    'QC: hook=' + qc.hook_score,
    'clarity=' + qc.clarity_score,
    'originality=' + qc.originality_score,
    'practical=' + qc.practical_value_score,
    'risk=' + qc.risk_level,
  ].join(' | ');

  const reviewHeader = [
    '[REVIEW STAGE]',
    'Session: ' + sessionToken,
    qcSummary,
    'QC feedback: ' + safeText(qc.feedback, 'Chưa có feedback QC.'),
    'Lệnh nhanh: tiep | dung | doi <noi_dung_muon_sua>',
    'Hoặc bấm button bên dưới.',
  ].join('\n');

  await sendLongReviewPreview(reviewHeader, reviewText);
  await sendTelegramMessage('Chọn hành động cho bản review:', reviewButtons);

  const decision = await waitForReviewerAction('rvw', sessionToken, offset, reviewerTimeoutSeconds);
  offset = decision.offset;
  commandLogs.push({ stage: 'review', ...decision, round: reviewRound });

  if (decision.action === 'stop') {
    reviewerStopped = true;
    break;
  }

  if (decision.action === 'continue') {
    break;
  }

  const instruction = safeText(decision.instruction, 'Làm lại bản review với văn phong rõ ràng hơn và bám sát ý sách.');
  await sendTelegramMessage('Đang cập nhật review theo yêu cầu: ' + instruction.slice(0, 500));

  try {
    const revisedReview = await reviseReview(reviewText, instruction);
    reviewText = revisedReview;
    reviewIntro = extractSectionText(reviewText, 'intro');
    reviewOutro = extractSectionText(reviewText, 'outro');
    qc = await runQc(reviewText, reviewIntro, reviewOutro);
  } catch (error) {
    await sendTelegramMessage('Không thể sửa review bằng AI: ' + String(error?.message ?? error).slice(0, 700));
  }

  reviewRound += 1;
}

if (!reviewerStopped) {
  await sendTelegramMessage('[METADATA STAGE] Đang tạo metadata (title/caption/thumbnail/hashtags)...');

  try {
    metadata = await generateMetadataBundle(reviewText, '', null);
    responseBase.metadata_status = 'generated';
  } catch (error) {
    responseBase.metadata_status = 'fallback';
    responseBase.metadata_error = String(error?.message ?? error);
    metadata = {
      title: 'Tiêu đề video',
      caption: 'Caption video',
      thumbnail_text: 'Thumbnail text',
      hashtags: ['#bookreview', '#selfhelp'],
    };
  }

  const maxMetadataAdjustRounds = 6;
  let metadataRound = 0;
  while (metadataRound <= maxMetadataAdjustRounds) {
    const metadataPreview = [
      '[METADATA BUNDLE]',
      'Session: ' + sessionToken,
      'Title: ' + metadata.title,
      'Caption: ' + metadata.caption,
      'Thumbnail: ' + metadata.thumbnail_text,
      'Hashtags: ' + metadata.hashtags.join(' '),
      'Lệnh nhanh: tiep | dung | doi <title/caption/hashtag/thumbnail + chi tiet>',
      'Khi bạn gõ doi, hệ thống tự thêm "Những thứ khác giữ nguyên".',
    ].join('\n');

    await sendTelegramMessage(metadataPreview);
    await sendTelegramMessage('Chọn hành động cho metadata:', metadataButtons);

    const decision = await waitForReviewerAction('meta', sessionToken, offset, reviewerTimeoutSeconds);
    offset = decision.offset;
    commandLogs.push({ stage: 'metadata', ...decision, round: metadataRound });

    if (decision.action === 'stop') {
      reviewerStopped = true;
      break;
    }

    if (decision.action === 'continue') {
      break;
    }

    const instruction = safeText(
      decision.instruction,
      'Làm lại metadata rõ ràng hơn, tập trung lợi ích thực tế, tránh clickbait.'
    );
    const adjustedInstruction = ensureKeepOthersInstruction(instruction);

    await sendTelegramMessage('Đang cập nhật metadata theo yêu cầu: ' + instruction.slice(0, 500));

    try {
      metadata = await generateMetadataBundle(reviewText, adjustedInstruction, metadata);
      responseBase.metadata_status = 'generated';
      responseBase.metadata_error = null;
    } catch (error) {
      responseBase.metadata_status = 'fallback';
      responseBase.metadata_error = String(error?.message ?? error);
      await sendTelegramMessage('Không thể cập nhật metadata: ' + responseBase.metadata_error.slice(0, 700));
    }

    metadataRound += 1;
  }
}

const finalStopReason = reviewerStopped
  ? 'reviewer_stopped'
  : String(input.stop_reason ?? 'completed');

const finalPayload = {
  review: reviewText,
  qc: {
    checks: qc.qc_checks,
    issues: qc.qc_issues,
    feedback: qc.feedback,
    score_warnings: qc.score_warnings,
    hook_score: qc.hook_score,
    clarity_score: qc.clarity_score,
    originality_score: qc.originality_score,
    practical_value_score: qc.practical_value_score,
    risk_level: qc.risk_level,
    qc_status: qc.qc_status,
    qc_error: qc.qc_error,
  },
  metadata,
  reviewer: {
    session_token: sessionToken,
    stopped: reviewerStopped,
    commands: commandLogs,
  },
};

const finalMessage = [
  reviewText,
  '---',
  'Book Review Output (JSON)',
  '~~~json',
  JSON.stringify(finalPayload, null, 2),
  '~~~',
].join('\n\n');

return {
  ...input,
  ...qc,
  full_review: reviewText,
  review_intro: reviewIntro,
  review_outro: reviewOutro,
  metadata_status: responseBase.metadata_status,
  metadata_error: responseBase.metadata_error,
  metadata,
  message: finalMessage,
  stop_reason: finalStopReason,
  reviewer_session_token: sessionToken,
  reviewer_decision: reviewerStopped ? 'stop' : 'continue',
  reviewer_gate_status: reviewerStopped ? 'stopped' : 'completed',
  reviewer_commands: commandLogs,
  video_title: metadata?.title ?? '',
  video_caption: metadata?.caption ?? '',
  video_thumbnail_text: metadata?.thumbnail_text ?? '',
  video_hashtags: Array.isArray(metadata?.hashtags) ? metadata.hashtags : [],
};

const stopReason = String($json.stop_reason ?? 'unknown');
const status = stopReason === 'completed' ? 'success' : 'failed';
const turnCount = Number($json.turn_count ?? 0);
const userInput = String($json.user_input ?? '').trim();
const riskLevel = String($json.risk_level ?? 'unknown');
const metadataStatus = String($json.metadata_status ?? 'unknown');

const scoreValues = [
  Number($json.hook_score),
  Number($json.clarity_score),
  Number($json.originality_score),
  Number($json.practical_value_score),
].filter((value) => Number.isFinite(value));

const avgScore = scoreValues.length
  ? Math.round((scoreValues.reduce((sum, value) => sum + value, 0) / scoreValues.length) * 10) / 10
  : null;

const summary = status === 'success'
  ? 'Book review completed in ' + turnCount + ' turn(s). risk=' + riskLevel + ', metadata=' + metadataStatus
  : 'Book review ended with stop_reason=' + stopReason + '. risk=' + riskLevel + ', metadata=' + metadataStatus;

const detailsParts = [
  $json.model ? 'model=' + $json.model : null,
  'turn_count=' + turnCount,
  'stop_reason=' + stopReason,
  'risk=' + riskLevel,
  'metadata_status=' + metadataStatus,
  avgScore !== null ? 'avg_score=' + avgScore : null,
  userInput ? 'user_input=' + userInput.slice(0, 120) : null,
].filter(Boolean);

if ($json.fallback_used === true && $json.fallback_model) {
  detailsParts.push('fallback_used=' + $json.fallback_model);
}

const scoreWarnings = Array.isArray($json.score_warnings) ? $json.score_warnings : [];
if (scoreWarnings.length > 0) {
  detailsParts.push('score_warnings=' + scoreWarnings.slice(0, 3).join('; '));
}

const message = String($json.message ?? '').trim();
if (message) {
  detailsParts.push('message=' + message.slice(0, 220));
}

return [{
  json: {
    status,
    source_workflow: 'Book Review Gemini via CLIProxyAPI',
    summary,
    details: detailsParts.join(' | '),
    notify_targets: String($json.notify_targets ?? 'telegram'),
    telegram_bot_token: String($json.telegram_bot_token ?? '').trim(),
    telegram_chat_id: String($json.telegram_chat_id ?? '').trim(),
    ggchat_webhook_url: String($json.ggchat_webhook_url ?? '').trim(),
    timestamp: new Date().toISOString(),
  },
}];

const input = $json ?? {};

return {
  message: String(input.message ?? '').trim() || 'Done.',
  stop_reason: String(input.stop_reason ?? 'completed'),
  reviewer_decision: String(input.reviewer_decision ?? 'continue'),
  risk_level: String(input.risk_level ?? 'med'),
  video_title: String(input.video_title ?? ''),
  video_caption: String(input.video_caption ?? ''),
  video_thumbnail_text: String(input.video_thumbnail_text ?? ''),
  video_hashtags: Array.isArray(input.video_hashtags) ? input.video_hashtags : [],
};
